import React from "react";
import { Link } from "react-router-dom";
import Navbar from "../components/Navbar";

function Home() {
  return (
    <div>
      <Navbar />

      <div style={{ padding: "40px" }}>
        <h1>Website đặt sân bóng và tìm đồng đội</h1>
        <p>
          Người dùng có thể xem sân, đặt sân và tham gia các trận đấu bóng đá.
        </p>

        <div style={{ display: "flex", gap: "16px", marginTop: "20px" }}>
          <Link to="/fields">
            <button>Xem danh sách sân</button>
          </Link>

          <Link to="/admin/bookings">
            <button>Xem booking</button>
          </Link>
        </div>
      </div>
    </div>
  );
}

export default Home;
